// menu-pdf-upload.component.ts
import {
  Component, Input, Output, EventEmitter, inject, signal, OnInit
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { MenuArService, MenuPdf } from '../../../services/Menu-PDF/menu-ar.service';

@Component({
  selector: 'app-menu-pdf-upload',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './menu-pdf-upload.component.html',
  styleUrl: './menu-pdf-upload.component.css'
})
export class MenuPdfUploadComponent implements OnInit {
  @Input({ required: true }) menuId!: string;
  @Output() editZones   = new EventEmitter<MenuPdf>();
  @Output() pdfUploaded = new EventEmitter<MenuPdf>();

  private arService = inject(MenuArService);

  pdfs       = signal<MenuPdf[]>([]);
  uploading  = signal(false);
  deleting   = signal(false);
  isDragging = signal(false);
  error      = signal<string | null>(null);
  successMsg = signal<string | null>(null);
  selectedId = signal<string | null>(null);

  async ngOnInit() {
    await this.arService.loadPdfsByMenu(this.menuId);
    this.pdfs.set(this.arService.getPdfsByMenu(this.menuId));
  }

  statusLabel(s: MenuPdf['status']): string {
    const map: Record<string, string> = {
      uploading:  'In caricamento',
      processing: 'Elaborazione',
      ready:      'Pronto',
      error:      'Errore',
    };
    return map[s] ?? s;
  }

  statusClass(s: MenuPdf['status']): string {
    if (s === 'ready') return 'active';
    if (s === 'error') return 'warning';
    return '';
  }

  selectPdf(id: string) { this.selectedId.set(id); }
  isSelected(id: string): boolean { return this.selectedId() === id; }

  onDragOver(e: DragEvent)  { e.preventDefault(); this.isDragging.set(true); }
  onDragLeave()              { this.isDragging.set(false); }

  onDrop(e: DragEvent) {
    e.preventDefault();
    this.isDragging.set(false);
    const f = e.dataTransfer?.files?.[0];
    if (f) this.processFile(f);
  }

  onFileChange(e: Event) {
    const f = (e.target as HTMLInputElement).files?.[0];
    if (f) this.processFile(f);
    (e.target as HTMLInputElement).value = '';
  }

  async confirmDelete(pdf: MenuPdf) {
    if (!confirm('Eliminare questo PDF e tutte le zone associate?')) return;
    this.deleting.set(true);
    const ok = await this.arService.deleteMenuPdf(pdf.id, pdf.file_path);
    if (ok) {
      this.pdfs.update(l => l.filter(p => p.id !== pdf.id));
      if (this.selectedId() === pdf.id) this.selectedId.set(null);
    }
    this.deleting.set(false);
  }

  get dropzoneLabel(): string {
    return this.pdfs().length === 0 ? 'Carica il PDF del menu' : 'Aggiungi un altro PDF';
  }

  private async processFile(file: File) {
    this.error.set(null);
    this.successMsg.set(null);

    if (file.type !== 'application/pdf') {
      this.error.set('Il file deve essere un PDF.');
      return;
    }
    if (file.size > 20 * 1024 * 1024) {
      this.error.set('File troppo grande (max 20 MB).');
      return;
    }

    this.uploading.set(true);
    const result = await this.arService.uploadMenuPdf(this.menuId, file);
    this.uploading.set(false);

    if (!result) {
      this.error.set('Errore nel caricamento. Riprova.');
      return;
    }

    this.pdfs.update(l => [result, ...l]);
    this.successMsg.set('PDF caricato! Clicca ▣ per associare i piatti alle zone.');
    this.pdfUploaded.emit(result);
    setTimeout(() => this.successMsg.set(null), 6000);
  }
}